<template>
  <div class="authory-box">
    <SpRouterView>
      <SpFilterForm :model="queryParams" @onSearch="onSearch" @onReset="onSearch">
        <SpFilterFormItem prop="status" label="審批狀態:">
          <el-select v-model="queryParams.status" placeholder="請選擇審批狀態">
            <el-option
              v-for="(item, index) in approveStatusList"
              :key="index"
              :label="item.name"
              :value="item.value"
            />
          </el-select>
        </SpFilterFormItem>
        <SpFilterFormItem prop="login_name" label="帳戶名稱:">
          <el-input v-model="queryParams.login_name" placeholder="請輸入帳戶名稱" />
        </SpFilterFormItem>
        <SpFilterFormItem prop="queryTime" label="申請日期:">
          <el-date-picker
            v-model="queryParams.queryTime"
            type="daterange"
            format="yyyy-MM-dd"
            value-format="yyyy-MM-dd"
            start-placeholder="開始日期"
            end-placeholder="結束日期"
          />
        </SpFilterFormItem>
      </SpFilterForm>
      <SpFinder
        ref="finder"
        url="/datapass"
        no-selection
        :fixed-row-action="true"
        row-actions-align="left"
        :setting="setting"
        :hooks="{
          beforeSearch: beforeSearch
        }"
      />
    </SpRouterView>
  </div>
</template>
<script>
import moment from 'moment'
import { createSetting } from '@shopex/finder'
export default {
  data() {
    return {
      queryParams: {
        login_name: '',
        status: '',
        queryTime: []
      },
      approveStatusList: [
        { name: '全部', value: undefined },
        { name: '待審批', value: '0' },
        { name: '已通過', value: '1' },
        { name: '未通過', value: '2' }
      ],
      setting: createSetting({
        actions: [
          {
            name: '審批',
            key: 'detail',
            type: 'button',
            buttonType: 'text',
            visible: (row) => {
              return row.status == '0'
            },
            action: {
              handler: async ([row]) => {
                const { pass_id, operator_id } = row
                this.$router.push({
                  path: this.matchHidePage('approve'),
                  query: { pass_id, operator_id }
                })
              }
            }
          }
        ],
        columns: [
          {
            name: '帳戶名稱',
            key: 'login_name'
          },
          {
            name: '帳戶權限',
            key: 'operator_type',
            formatter: (value, row, col) => {
              return value === 'staff' ? '平台管理員' : '店鋪管理員'
            }
          },
          {
            name: '申請時間',
            key: 'create_time',
            formatter: (value, row, col) => {
              return moment(value * 1000).format('YYYY-MM-DD HH:mm:ss')
            }
          },
          {
            name: '申請結果',
            key: 'status',
            render: (h, scope) => {
              if (scope.row.status == '1' || scope.row.status == '2') {
                return h(
                  'el-tag',
                  {
                    props: {
                      type: scope.row.status == '1' ? 'success' : 'danger',
                      effect: 'dark',
                      size: 'small'
                    }
                  },
                  scope.row.status == '1' ? '通過' : '拒絕'
                )
              } else {
                return ''
              }
            }
          }
        ]
      })
    }
  },
  methods: {
    beforeSearch(params) {
      const [startTime, endTime] = this.queryParams.queryTime
      if (startTime) {
        params['start_time'] = moment(startTime).unix()
      }
      if (endTime) {
        params['end_time'] = moment(endTime).unix()
      }
      return params
    },
    onSearch() {
      this.$refs.finder.refresh(true)
    }
  }
}
</script>
<style lang="scss"></style>
